import{_ as a,o as t,c as n,ae as i}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Flutter SDK Basic Integration","description":"","frontmatter":{"title":"Flutter SDK Basic Integration","slug":"flutter-sdk-basic-integration"},"headers":[],"relativePath":"developer-hub/flutter-sdk-basic-integration.md","filePath":"developer-hub/flutter-sdk-basic-integration.md"}'),r={name:"developer-hub/flutter-sdk-basic-integration.md"};function s(o,e,l,c,d,p){return t(),n("div",null,[...e[0]||(e[0]=[i(`<div class="tip custom-block"><p class="custom-block-title">SDK Stats</p><ul><li><strong>Open Source Github Repo:</strong> <a href="https://github.com/BranchMetrics/flutter_branch_sdk" target="_blank" rel="noreferrer">https://github.com/BranchMetrics/flutter_branch_sdk</a></li><li><a href="https://github.com/BranchMetrics/flutter_branch_sdk/tree/master/example" target="_blank" rel="noreferrer"><strong>Sample App</strong></a></li><li><a href="https://github.com/BranchMetrics/flutter_branch_sdk/blob/master/pubspec.yaml" target="_blank" rel="noreferrer">Flutter Version Support</a>: v1.22.0+</li></ul></div><h3 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h3><p>In order to implement the Branch SDK into your Flutter app, you need to have/complete the following:</p><ol><li>Created a <a href="https://dashboard.branch.io/" target="_blank" rel="noreferrer">Branch Dashboard</a>.</li><li><a href="https://docs.flutter.dev/get-started/install" target="_blank" rel="noreferrer">Flutter installed</a>.</li></ol><h3 id="_1-configure-branch" tabindex="-1">1. Configure Branch <a class="header-anchor" href="#_1-configure-branch" aria-label="Permalink to &quot;1. Configure Branch&quot;">​</a></h3><p>Universal for all platforms, you first need to configure your app in Branch. Once logged in, navigate to your app settings to <a href="./configure-default-link-behaviors.html">configure your links and redirects</a>:</p><ul><li><strong>New Branch</strong>: In the left-hand navigation, go to <strong>Configuration</strong> and click on <strong>Link Controls</strong>. Navigate to the <strong>Link Routing Rules</strong> tab to configure your app settings.</li><li><strong>Legacy Branch</strong>: Navigate to the <a href="https://dashboard.branch.io/configuration/general" target="_blank" rel="noreferrer">App Settings</a> screen.</li></ul><h4 id="default-url" tabindex="-1">Default URL <a class="header-anchor" href="#default-url" aria-label="Permalink to &quot;Default URL&quot;">​</a></h4><p>Set a URL here to designate where the user will be redirected to when opening a Branch Link on web.</p><h4 id="android" tabindex="-1">Android <a class="header-anchor" href="#android" aria-label="Permalink to &quot;Android&quot;">​</a></h4><p>Input your Android URI scheme to direct the app to open for users clicking on links with the app installed. If you have Android App Links enabled, input your SHA256 Cert Fingerprint as well.</p><p>Be sure to set your Google Play store listing as the fallback redirect for users clicking on links without the app installed.</p><p>Additional details on setting Android Redirects can be found <a href="./android-basic-integration.html#configure-branch-dashboard">here</a>.</p><p>To configure Android settings in Branch:</p><ul><li><strong>New Branch</strong>: In the left-hand navigation, go to <strong>Configuration</strong> and click on <strong>Link Controls</strong>. Navigate to the <strong>Link Routing Rules</strong> tab, then find the <strong>Mobile Routing</strong> section and select <strong>Android</strong>.</li><li><strong>Legacy Branch</strong>: Navigate to the <a href="https://dashboard.branch.io/configuration/general" target="_blank" rel="noreferrer">Configuration page</a> and find the Android section.</li></ul><h4 id="ios" tabindex="-1">iOS <a class="header-anchor" href="#ios" aria-label="Permalink to &quot;iOS&quot;">​</a></h4><p>Input your iOS URI Schemes to direct the app to open for users clicking on links with the app installed. Add your app&#39;s bundle identifiers and Apple App Prefix for Universal Links.</p><p>Be sure to set your App Store listing as the fallback redirect for users clicking on links without the app installed.</p><p>Additional details on setting iOS Redirects can be found <a href="./ios-basic-integration.html#1-configure-the-branch-dashboard">here</a>.</p><p>To configure iOS settings in Branch:</p><ul><li><strong>New Branch</strong>: In the left-hand navigation, go to <strong>Configuration</strong> and click on <strong>Link Controls</strong>. Navigate to the <strong>Link Routing Rules</strong> tab, then find the <strong>Mobile Routing</strong> section and select <strong>iOS</strong>.</li><li><strong>Legacy Branch</strong>: Navigate to the <a href="https://dashboard.branch.io/configuration/general" target="_blank" rel="noreferrer">Configuration page</a> and find the iOS section.</li></ul><h3 id="_2-configure-native-platforms" tabindex="-1">2. Configure Native Platforms <a class="header-anchor" href="#_2-configure-native-platforms" aria-label="Permalink to &quot;2. Configure Native Platforms&quot;">​</a></h3><p>In order to set up Branch, you will need to configure each platform to prepare for session initialization.</p><h4 id="android-1" tabindex="-1">Android <a class="header-anchor" href="#android-1" aria-label="Permalink to &quot;Android&quot;">​</a></h4><p>For Android, you need to <a href="./android-basic-integration.html#configure-app">configure your AndroidManifest.xml file,</a></p><h4 id="ios-1" tabindex="-1">iOS <a class="header-anchor" href="#ios-1" aria-label="Permalink to &quot;iOS&quot;">​</a></h4><p>For iOS, you need to configure the following:</p><ul><li><a href="./ios-basic-integration.html#configure-bundle-identifier">Bundle Identifier(s)</a></li><li><a href="./ios-basic-integration.html#2-configure-associated-domains">Associated Domains</a></li><li><a href="./ios-basic-integration.html#3-configure-entitlements">Entitlements</a></li><li><a href="./ios-basic-integration.html#4-configure-infoplist">Info.plist</a></li></ul><h4 id="web" tabindex="-1">Web <a class="header-anchor" href="#web" aria-label="Permalink to &quot;Web&quot;">​</a></h4><p>For Web, you need to add the Branch Javascript in your <code>web\\index.html</code> at the top of your<code>&lt;&gt;</code> <strong>tag</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;script&gt;</span></span>
<span class="line"><span>        (function(b,r,a,n,c,h,_,s,d,k){if(!b[n]||!b[n]._q){for(;s&lt;_.length;)c(h,_[s++]);d=r.createElement(a);d.async=1;d.src=&quot;https://cdn.branch.io/branch-latest.min.js&quot;;k=r.getElementsByTagName(a)[0];k.parentNode.insertBefore(d,k);b[n]=h}})(window,document,&quot;script&quot;,&quot;branch&quot;,function(b,r){b[r]=function(){b._q.push([r,arguments])}},{_q:[],_v:1},&quot;addListener applyCode autoAppIndex banner closeBanner closeJourney creditHistory credits data deepview deepviewCta first getCode init link logout redeem referrals removeListener sendSMS setBranchViewData setIdentity track validateCode trackCommerceEvent logEvent disableTracking&quot;.split(&quot; &quot;), 0);</span></span>
<span class="line"><span>        branch.init(&#39;key_live_YOUR_KEY_GOES_HERE&#39;);</span></span>
<span class="line"><span>        &lt;/script&gt;</span></span></code></pre></div><h3 id="_3-install-branch" tabindex="-1">3. Install Branch <a class="header-anchor" href="#_3-install-branch" aria-label="Permalink to &quot;3. Install Branch&quot;">​</a></h3><h4 id="add-the-dependency" tabindex="-1">Add the Dependency <a class="header-anchor" href="#add-the-dependency" aria-label="Permalink to &quot;Add the Dependency&quot;">​</a></h4><p>Run the following command in terminal <code>flutter pub get</code> to add the Flutter Branch SDK package.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>flutter pub add flutter_branch_sdk</span></span></code></pre></div><p>This will add the Flutter Branch SDK to your project&#39;s <em>pubspec</em> file.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>dependencies:</span></span>
<span class="line"><span>        flutter_branch_sdk: ^5.0.0</span></span></code></pre></div><h4 id="import-branch-package" tabindex="-1">Import Branch Package <a class="header-anchor" href="#import-branch-package" aria-label="Permalink to &quot;Import Branch Package&quot;">​</a></h4><p>In your Dart code, import Branch:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>import &#39;package:flutter_branch_sdk/flutter_branch_sdk.dart&#39;;</span></span></code></pre></div><h3 id="_4-initialize-branch" tabindex="-1">4. Initialize Branch <a class="header-anchor" href="#_4-initialize-branch" aria-label="Permalink to &quot;4. Initialize Branch&quot;">​</a></h3><p>In your main Dart file, you need to initialize the Branch Session listener before being able to use any of the SDK methods. A listener should be called early on in your <code>initState()</code> method:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>FlutterBranchSdk.listSession().listen((data) {</span></span>
<span class="line"><span>        ...</span></span>
<span class="line"><span>        });</span></span></code></pre></div><h4 id="validate-integration" tabindex="-1">Validate Integration <a class="header-anchor" href="#validate-integration" aria-label="Permalink to &quot;Validate Integration&quot;">​</a></h4><p>After initializing Branch, you can validate your integration verify your keys, schemes, etc. using the <code>validateSDKIntegration()</code> method. Do not forget to remove this line after validation.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>FlutterBranchSdk.validateSDKIntegration();</span></span></code></pre></div><h3 id="_5-configure-deep-linking" tabindex="-1">5. Configure Deep Linking <a class="header-anchor" href="#_5-configure-deep-linking" aria-label="Permalink to &quot;5. Configure Deep Linking&quot;">​</a></h3><p>Firstly, when your Branch Session is initialized, the you&#39;ll want to configure your deep linking routing logic.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>StreamSubscription&lt;Map&gt; streamSubscription = FlutterBranchSdk.listSession().listen((data) {</span></span>
<span class="line"><span>        if (data.containsKey(&quot;+clicked_branch_link&quot;) &amp;&amp;</span></span>
<span class="line"><span>        data[&quot;+clicked_branch_link&quot;] == true) {</span></span>
<span class="line"><span>        //Link clicked. Add logic to get link data and route user to correct screen</span></span>
<span class="line"><span>        print(&#39;Custom string: \${data[&quot;custom_string&quot;]}&#39;);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>        }, onError: (error) {</span></span>
<span class="line"><span>        PlatformException platformException = error as PlatformException;</span></span>
<span class="line"><span>        print(</span></span>
<span class="line"><span>        &#39;InitSession error: \${platformException.code} - \${platformException.message}&#39;);</span></span>
<span class="line"><span>        });</span></span></code></pre></div>`,49)])])}const g=a(r,[["render",s]]);export{u as __pageData,g as default};
